int main() {
    int T, finish, distancetoBolt, tigerAccelaration, boltSpeed;
    scanf("%d", &T);
    while (T--) {
        scanf("%d%d%d%d", &finish, &distancetoBolt, &tigerAccelaration, &boltSpeed);
        double time = (double)distancetoBolt / boltSpeed;
        double tigerTime = sqrt((2 * (double)distancetoBolt) / tigerAccelaration);
        if (time <= tigerTime) printf("Bolt\n");
        else printf("Tiger\n");
    }
    return 0;
}

