code.Java:
public class Main {
    public static void main(String[] args) {
        java.util.Scanner scanner = new java.util.Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int finish = scanner.nextInt();
            int distancetoBolt = scanner.nextInt();
            int tigerAccelaration = scanner.nextInt();
            int boltSpeed = scanner.nextInt();
            double time = (double)distancetoBolt / boltSpeed;
            double tigerTime = Math.sqrt((2 * (double)distancetoBolt) / tigerAccelaration);
            if (time <= tigerTime) System.out.println("Bolt");
            else System.out.println("Tiger");
        }
    }
}

